import React, { useState, useEffect, useContext } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
  Box, Container, Typography, Card, CardContent, Grid,
  Table, TableBody, TableCell, TableContainer, TableHead, TableRow,
  Paper, Chip, Avatar, IconButton, Tooltip, TextField, InputAdornment,
  Select, MenuItem, FormControl, InputLabel, Button, Dialog, DialogTitle,
  DialogContent, DialogActions, List, ListItem, ListItemText, Divider,
  Alert, CircularProgress, Badge, AppBar, Toolbar
} from '@mui/material';
import { ArrowBack, RefreshRounded } from '@mui/icons-material';
import { toast } from 'react-toastify';

const UserDashboardView = () => {
    const { userId } = useParams();
    const navigate = useNavigate();
    const [loading, setLoading] = useState(false);
    const [userData, setUserData] = useState(null);
    const [closingTradeId, setClosingTradeId] = useState(null);

    const loadUserData = async () => {
        if (!loading) setLoading(true);
        try {
            const response = await fetch(`/api/admin/user/${userId}/dashboard`, {
                method: 'GET',
                credentials: 'include',
                headers: { 'Content-Type': 'application/json' },
            });
            if (!response.ok) {
                throw new Error(`HTTP error! status: ${response.status}`);
            }
            const data = await response.json();
            setUserData(data);
        } catch (error) {
            console.error('Erro ao carregar dados do usuário:', error);
            toast.error('Não foi possível carregar os dados do usuário.');
            navigate('/admin');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        loadUserData();
        const interval = setInterval(loadUserData, 30000); // Atualiza a cada 30 segundos
        return () => clearInterval(interval); // Limpa o intervalo quando o componente é desmontado
    }, [userId]);
    
    const handleCloseTrade = async (tradeId) => {
        if (closingTradeId) return;
        setClosingTradeId(tradeId);
        try {
            const response = await fetch(`/api/admin/trades/${tradeId}/close`, {
                method: 'POST',
                credentials: 'include',
            });
            const data = await response.json();
            if (!response.ok) {
                throw new Error(data.message || 'Erro ao fechar a operação.');
            }
            toast.success('Ordem de fechamento enviada com sucesso!');
            await loadUserData();
        } catch (error) {
            console.error('Erro ao fechar trade:', error);
            toast.error(`Falha ao fechar a operação: ${error.message}`);
        } finally {
            setClosingTradeId(null);
        }
    };

    const formatCurrency = (value) => {
        return new Intl.NumberFormat('pt-BR', {
          style: 'currency',
          currency: 'USD',
          minimumFractionDigits: 2,
          maximumFractionDigits: 4
        }).format(value || 0);
    };
    
    const formatDate = (dateString) => {
        if (!dateString) return 'N/A';
        return new Date(dateString).toLocaleString('pt-BR');
    };

    if (loading || !userData) {
        return (
            <Box sx={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh' }}>
                <CircularProgress />
            </Box>
        );
    }

    const { user_info, stats, open_positions, closed_trades, operational_balance_usd } = userData;

    return (
        <Box sx={{ display: 'flex' }}>
             <AppBar position="fixed" sx={{ zIndex: (theme) => theme.zIndex.drawer + 1, bgcolor: '#1a1a1a' }}>
                <Toolbar>
                    <IconButton edge="start" color="inherit" onClick={() => navigate('/admin')} sx={{ mr: 2 }}>
                        <ArrowBack />
                    </IconButton>
                    <Typography variant="h6" noWrap component="div" sx={{ flexGrow: 1 }}>
                        Visão do Dashboard - {user_info.full_name}
                    </Typography>
                    <Tooltip title="Atualizar Dados">
                        <IconButton onClick={loadUserData} color="inherit" disabled={loading}>
                        <RefreshRounded />
                        </IconButton>
                    </Tooltip>
                </Toolbar>
            </AppBar>
            <Box component="main" sx={{ flexGrow: 1, p: 3, bgcolor: '#121212', minHeight: '100vh', mt: '64px' }}>
                <Container maxWidth="xl" sx={{ mt: 4, mb: 4 }}>
                    {/* Cards de Estatísticas do Usuário */}
                    <Grid container spacing={3} sx={{ mb: 3 }}>
                        <Grid item xs={12} sm={6} md={3}>
                            <Card sx={{ bgcolor: '#333', border: '1px solid #555' }}>
                                <CardContent>
                                    <Typography color="textSecondary" gutterBottom>Saldo Operacional</Typography>
                                    <Typography variant="h5" sx={{ color: '#2196f3' }}>
                                        {formatCurrency(operational_balance_usd)}
                                    </Typography>
                                </CardContent>
                            </Card>
                        </Grid>
                        {/* Outros cards de estatísticas aqui */}
                    </Grid>

                    {/* Posições Abertas */}
                    {open_positions && open_positions.length > 0 ? (
                        <Box sx={{ mb: 3 }}>
                          <Typography variant="h6" sx={{ color: '#f0b90b', mb: 2 }}>Posições Abertas ({open_positions.length})</Typography>
                          <TableContainer component={Paper} sx={{ bgcolor: '#1e1e1e' }}>
                            <Table>
                              <TableHead>
                                <TableRow>
                                  <TableCell sx={{ color: '#f0b90b' }}>Símbolo</TableCell>
                                  <TableCell sx={{ color: '#f0b90b' }}>Lado</TableCell>
                                  <TableCell sx={{ color: '#f0b90b' }}>Tamanho</TableCell>
                                  <TableCell sx={{ color: '#f0b90b' }}>Preço de Entrada</TableCell>
                                  <TableCell sx={{ color: '#f0b90b' }}>PnL</TableCell>
                                  <TableCell sx={{ color: '#f0b90b' }}>ROE</TableCell>
                                  <TableCell sx={{ color: '#f0b90b' }}>Ações</TableCell>
                                </TableRow>
                              </TableHead>
                              <TableBody>
                                {open_positions.map((pos) => (
                                  <TableRow key={pos.id}>
                                    <TableCell sx={{ color: 'white' }}>{pos.symbol}</TableCell>
                                    <TableCell sx={{ color: pos.side.toLowerCase() === 'long' ? 'success.main' : 'error.main' }}>{pos.side}</TableCell>
                                    <TableCell sx={{ color: 'white' }}>{pos.size}</TableCell>
                                    <TableCell sx={{ color: 'white' }}>{formatCurrency(pos.entry_price)}</TableCell>
                                    <TableCell sx={{ color: pos.pnl && pos.pnl >= 0 ? 'success.main' : 'error.main' }}>
                                      {pos.pnl ? formatCurrency(pos.pnl) : '-'}
                                    </TableCell>
                                    <TableCell sx={{ color: pos.roe_percentage >= 0 ? 'success.main' : 'error.main' }}>
                                        {pos.roe_percentage.toFixed(2)}%
                                    </TableCell>
                                    <TableCell>
                                        <Button
                                            variant="contained"
                                            color="error"
                                            size="small"
                                            onClick={() => handleCloseTrade(pos.id)}
                                            disabled={closingTradeId === pos.id}
                                        >
                                            {closingTradeId === pos.id ? <CircularProgress size={20} color="inherit" /> : 'Encerrar'}
                                        </Button>
                                    </TableCell>
                                  </TableRow>
                                ))}
                              </TableBody>
                            </Table>
                          </TableContainer>
                        </Box>
                    ) : (
                        <Box sx={{ mb: 3 }}>
                          <Typography variant="h6" sx={{ color: '#f0b90b', mb: 2 }}>Posições Abertas</Typography>
                          <Card sx={{ bgcolor: '#1e1e1e', color: 'gray', textAlign: 'center' }}>
                            <CardContent>
                              <Typography>Nenhuma posição aberta no momento.</Typography>
                            </CardContent>
                          </Card>
                        </Box>
                    )}

                    {/* Trades Fechados */}
                    <Typography variant="h6" sx={{ color: '#f0b90b', mb: 2 }}>Operações Fechadas Recentes</Typography>
                    <TableContainer component={Paper} sx={{ bgcolor: '#1e1e1e' }}>
                        <Table>
                            <TableHead>
                                <TableRow>
                                    <TableCell sx={{ color: '#f0b90b' }}>Símbolo</TableCell>
                                    <TableCell sx={{ color: '#f0b90b' }}>Lado</TableCell>
                                    <TableCell sx={{ color: '#f0b90b' }}>PnL</TableCell>
                                    <TableCell sx={{ color: '#f0b90b' }}>Data</TableCell>
                                </TableRow>
                            </TableHead>
                            <TableBody>
                            {closed_trades && closed_trades.length > 0 ? (
                                closed_trades.map(trade => (
                                    <TableRow key={trade.id}>
                                        <TableCell sx={{ color: 'white' }}>{trade.symbol}</TableCell>
                                        <TableCell sx={{ color: 'white' }}>{trade.side}</TableCell>
                                        <TableCell sx={{ color: trade.pnl >= 0 ? 'success.main' : 'error.main' }}>{formatCurrency(trade.pnl)}</TableCell>
                                        <TableCell sx={{ color: 'white' }}>{formatDate(trade.closed_at)}</TableCell>
                                    </TableRow>
                                ))
                            ) : (
                                <TableRow>
                                    <TableCell colSpan={4} align="center" sx={{ color: 'gray' }}>
                                        Nenhuma operação fechada encontrada.
                                    </TableCell>
                                </TableRow>
                            )}
                            </TableBody>
                        </Table>
                    </TableContainer>
                </Container>
            </Box>
        </Box>
    );
};

export default UserDashboardView;
